#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=205;//记得改数据范围 ！！！！ 
const ll inf=1e17;
int n,m,s,t,fir[N];//fir为弧优化数组 
struct node
{
	int v,w,fan;//fan记录反向边的位置（g[v][g[u][i].fan]就是g[u][i]的反向边） 
};
ll lev[N];
vector<node> g[N];
void add(int u,int v,ll w)
{
	g[u].push_back(node{v,w,g[v].size()});
	g[v].push_back(node{u,0,g[u].size()-1});//反向边只建一个w为0的
}
bool bfs()//顺便看一下图是不是联通的 
{
	for(int i=1;i<=N-3;i++)
	{
		lev[i]=inf;
		fir[i]=0;
	}
	queue<int> q;
	q.push(s);
	lev[s]=0;
	while(!q.empty())
	{
		int u=q.front();
		q.pop();
		for(int i=0;i<g[u].size();i++)
		{
			ll v=g[u][i].v,w=g[u][i].w;
			if((w>0)&&(lev[v]==inf))
			{
				q.push(v);
				lev[v]=lev[u]+1;
				if(v==t) return 1;
			}
		}
	}
	return 0;
}
ll dfs(int u,ll mn)//mn是目前找到的这条增广路的min 
{
	if(u==t) return mn;
	ll ans=0;
	for(int i=fir[u];i<g[u].size();i++)
	{
		fir[u]=i;
		ll v=g[u][i].v,w=g[u][i].w;
		if((w>0)&&(lev[v]==lev[u]+1))
		{
			ll num=dfs(v,min(mn,(ll)w));
			if(num==0) lev[v]=inf;
			g[u][i].w-=num;
			g[v][g[u][i].fan].w+=num;//反向边
			ans+=num;
			mn-=num;
		}
	}
	return ans;
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>m>>s>>t;
	for(int i=1;i<=m;i++)
	{
		ll u,v,w;
		cin>>u>>v>>w;
		add(u,v,w);
	}
	ll ans=0;
	while(bfs())
	{
		ans+=dfs(s,inf);
	}
	cout<<ans;
	return 0;
}
